import type { SelectOption } from '@linm-soft-org/linm-web-common-components';
import type { SearchInputConfig } from '@linm-soft-org/linm-web-common-components';
import { parseDepartmentOptions, type DepartmentLookupItem } from '../../utils/departmentField';
import { createStaticLookupSearchConfig } from './createStaticLookupSearchConfig';

/** Đơn vị — init-data `departmentOptions`, filter client (`department-field.md`). POST mã đơn vị. */
export function createDepartmentSearchConfig(
  options: SelectOption[],
): SearchInputConfig<DepartmentLookupItem> {
  const items = parseDepartmentOptions(options);
  return createStaticLookupSearchConfig({
    loadItems: () => items,
    getKey: item => item.code,
    getCode: item => item.code,
    getName: item => item.name,
    getFilterText: item => item.label,
  });
}

/** Đơn vị theo UUID — dùng khi API cần `departmentId` (`TscdDieuChuyenPage`). */
export function createDepartmentIdSearchConfig(
  options: SelectOption[],
): SearchInputConfig<DepartmentLookupItem> {
  const items = parseDepartmentOptions(options);
  return createStaticLookupSearchConfig({
    loadItems: () => items,
    getKey: item => item.id,
    getCode: item => item.code,
    getName: item => item.name,
    getFilterText: item => item.label,
  });
}
